sql:
SELECT species_id, AVG(capacity) AS average_capacity
FROM capacity_estimates
GROUP BY species_id;

SELECT estimate_id, species_id, life_stage_id, stream_id, reach_id, capacity, se, ci, methodology, estimation_date, estimated_by 
FROM capacity_estimates 
WHERE species_id = 5;

SELECT species_id, life_stage_id, capacity
FROM capacity_estimates
LIMIT 10;

SELECT stream_name 
FROM streams 
WHERE average_flow_rate = (SELECT MAX(average_flow_rate) FROM streams);

SELECT streams.stream_name, geospatial_data.geometry
FROM streams
INNER JOIN geospatial_data ON streams.stream_id = geospatial_data.stream_id;

SELECT *
FROM streams
WHERE water_quality < (SELECT AVG(water_quality) FROM streams);

SELECT streams.stream_name, stream_data.data
FROM streams
INNER JOIN stream_data ON streams.stream_id = stream_data.stream_id;

SELECT life_stage_name, description
FROM life_stages
WHERE growth_rate > 5;

SELECT species_name
FROM fish_species
WHERE species_id NOT IN (
    SELECT species_id
    FROM capacity_estimates
);

SELECT streams.stream_name, streams.last_survey_date, stream_reaches.reach_name, stream_reaches.last_survey_date 
FROM streams 
LEFT JOIN stream_reaches ON streams.stream_id = stream_reaches.stream_id;
